/**
 * Parse a SCIP symbol string into structured components
 *
 * Symbol format:
 *   <symbol> ::= <scheme> ' ' <package> ' ' (<descriptor>)+ | 'local ' <local-id>
 *   <package> ::= <manager> ' ' <package-name> ' ' <version>
 *
 * Descriptor suffixes:
 *   /  - namespace
 *   #  - type
 *   .  - term
 *   () - method (with optional disambiguator like ().disambiguator.)
 *   [] - type parameter
 *   () - parameter
 *   :  - meta
 *   !  - macro
 */
export function parseSymbol(symbol: string): ParsedSymbol {
  if (symbol.startsWith('local ')) {
    return {
      scheme: 'local',
      descriptors: [],
      isLocal: true,
      localId: symbol.slice(6),
    };
  }

  const parts = symbol.split(' ');
  if (parts.length < 4) {
    throw new Error(`Invalid symbol format: ${symbol}`);
  }

  const scheme = parts[0];
  const manager = parts[1];
  const packageName = parts[2];
  const version = parts[3];
  const descriptorStr = parts.slice(4).join(' ');

  const descriptors = parseDescriptors(descriptorStr);

  return {
    scheme,
    package: {
      manager,
      name: packageName,
      version,
    },
    descriptors,
    isLocal: false,
  };
}

/**
 * Parse descriptor string into structured components
 */
function parseDescriptors(descriptorStr: string): SymbolDescriptor[] {
  const descriptors: SymbolDescriptor[] = [];
  let remaining = descriptorStr;

  while (remaining.length > 0) {
    const result = parseNextDescriptor(remaining);
    if (!result) break;
    descriptors.push(result.descriptor);
    remaining = result.remaining;
  }

  return descriptors;
}

/**
 * Parse the next descriptor from the string
 */
function parseNextDescriptor(str: string): { descriptor: SymbolDescriptor; remaining: string } | null {
  if (str.length === 0) return null;

  // Find the end of the name (look for suffix)
  let nameEnd = 0;
  let depth = 0;

  while (nameEnd < str.length) {
    const char = str[nameEnd];
    if (char === '(' || char === '[') {
      depth++;
    } else if (char === ')' || char === ']') {
      depth--;
    } else if (depth === 0 && isDescriptorSuffix(char)) {
      break;
    }
    nameEnd++;
  }

  const name = str.slice(0, nameEnd);
  const suffix = str[nameEnd];
  const rest = str.slice(nameEnd + 1);

  switch (suffix) {
    case '/':
      return { descriptor: { type: 'namespace', name }, remaining: rest };
    case '#':
      return { descriptor: { type: 'type', name }, remaining: rest };
    case '.':
      return { descriptor: { type: 'term', name }, remaining: rest };
    case ':':
      return { descriptor: { type: 'meta', name }, remaining: rest };
    case '!':
      return { descriptor: { type: 'macro', name }, remaining: rest };
    case '(': {
      // Method: name(). or name().disambiguator.
      const closeIdx = rest.indexOf(')');
      if (closeIdx === -1) {
        return { descriptor: { type: 'method', name }, remaining: '' };
      }
      const afterClose = rest.slice(closeIdx + 1);
      if (afterClose.startsWith('.')) {
        const disambiguatorEnd = afterClose.indexOf('.', 1);
        const disambiguator = disambiguatorEnd > 0
          ? afterClose.slice(1, disambiguatorEnd)
          : afterClose.slice(1);
        return {
          descriptor: { type: 'method', name, disambiguator },
          remaining: disambiguatorEnd > 0 ? afterClose.slice(disambiguatorEnd + 1) : '',
        };
      }
      return { descriptor: { type: 'method', name }, remaining: afterClose };
    }
    case '[': {
      // Type parameter: name[]
      const closeIdx = rest.indexOf(']');
      if (closeIdx === -1) {
        return { descriptor: { type: 'typeParameter', name }, remaining: '' };
      }
      return { descriptor: { type: 'typeParameter', name }, remaining: rest.slice(closeIdx + 1) };
    }
    default:
      // No suffix - treat as term
      return { descriptor: { type: 'term', name }, remaining: '' };
  }
}

/**
 * Check if character is a descriptor suffix
 */
function isDescriptorSuffix(char: string): boolean {
  return '/#.:!()[]'.includes(char);
}

/**
 * Determine node type from symbol descriptors
 */
function getNodeTypeFromDescriptors(descriptors: SymbolDescriptor[]): NodeType {
  if (descriptors.length === 0) return NodeType.Variable;

  const lastDescriptor = descriptors[descriptors.length - 1];

  switch (lastDescriptor.type) {
    case 'namespace':
      return NodeType.Namespace;
    case 'type':
      return NodeType.Class;
    case 'method':
      return NodeType.Method;
    case 'macro':
      return NodeType.Macro;
    case 'meta':
      return NodeType.Type;
    case 'typeParameter':
      return NodeType.Type;
    case 'parameter':
      return NodeType.Parameter;
    case 'term':
    default:
      return NodeType.Variable;
  }
}

/**
 * Generate a unique node ID from a symbol
 */
function generateNodeId(symbol: string): string {
  // Use the symbol itself as ID (it's already unique)
  return symbol;
}

/**
 * Generate a unique edge ID
 */
function generateEdgeId(sourceId: string, targetId: string, type: EdgeType): string {
  return `${type}:${sourceId}->${targetId}`;
}

/**
 * Extract node name from symbol
 */
function extractNodeName(parsed: ParsedSymbol): string {
  if (parsed.isLocal) {
    return parsed.localId || 'local';
  }
  if (parsed.descriptors.length === 0) {
    return parsed.scheme;
  }
  return parsed.descriptors[parsed.descriptors.length - 1].name;
}

/**
 * Build file path from symbol descriptors
 */
function buildFilePath(parsed: ParsedSymbol): string | undefined {
  if (parsed.isLocal || !parsed.descriptors.length) {
    return undefined;
  }

  // Find namespace descriptors to reconstruct path
  const pathParts: string[] = [];
  for (const desc of parsed.descriptors) {
    if (desc.type === 'namespace') {
      pathParts.push(desc.name);
    }
  }

  return pathParts.length > 0 ? pathParts.join('/') : undefined;
}

/**
 * Convert SCIP symbol information to Node
 */
function symbolInfoToNode(
  symbolInfo: ScipSymbolInformation,
  language: string,
  filePath: string
): Node {
  const parsed = parseSymbol(symbolInfo.symbol);

  return {
    id: generateNodeId(symbolInfo.symbol),
    type: getNodeTypeFromDescriptors(parsed.descriptors),
    name: extractNodeName(parsed),
    language,
    filePath,
    documentation: symbolInfo.documentation,
    signature: symbolInfo.signature_documentation?.text,
    isExternal: false,
  };
}

/**
 * Convert occurrence to Node (for definitions)
 */
function occurrenceToNode(
  occurrence: ScipOccurrence,
  language: string,
  filePath: string,
  defaultName: string
): Node | null {
  if (!occurrence.symbol) return null;

  const parsed = parseSymbol(occurrence.symbol);

  return {
    id: generateNodeId(occurrence.symbol),
    type: getNodeTypeFromDescriptors(parsed.descriptors),
    name: extractNodeName(parsed) || defaultName,
    language,
    filePath,
    line: occurrence.range[0],
    column: occurrence.range[1],
    endLine: occurrence.range.length === 3 ? occurrence.range[0] : occurrence.range[2],
    endColumn: occurrence.range.length === 3 ? occurrence.range[2] : occurrence.range[3],
    isExternal: false,
  };
}

/**
 * Check if occurrence is a definition
 */
function isDefinition(occurrence: ScipOccurrence): boolean {
  if (!occurrence.symbol_roles) return false;
  return (occurrence.symbol_roles & SymbolRole.Definition) !== 0;
}

/**
 * Check if occurrence is an import
 */
function isImport(occurrence: ScipOccurrence): boolean {
  if (!occurrence.symbol_roles) return false;
  return (occurrence.symbol_roles & SymbolRole.Import) !== 0;
}

/**
 * Check if occurrence is a reference
 */
function isReference(occurrence: ScipOccurrence): boolean {
  if (!occurrence.symbol_roles) return false;
  return (occurrence.symbol_roles & SymbolRole.ReadAccess) !== 0;
}

/**
 * Parse SCIP index and extract nodes and edges
 */
export function parseScipIndex(index: ScipIndex): ScipParseResult {
  const nodes = new Map<string, Node>();
  const edges: Edge[] = [];

  // Process each document
  for (const doc of index.documents) {
    processDocument(doc, nodes, edges);
  }

  // Process external symbols
  if (index.external_symbols) {
    for (const sym of index.external_symbols) {
      processExternalSymbol(sym, nodes);
    }
  }

  return {
    nodes: Array.from(nodes.values()),
    edges,
    metadata: {
      projectRoot: index.metadata?.project_root || '',
      toolName: index.metadata?.tool_info?.name,
      toolVersion: index.metadata?.tool_info?.version,
      protocolVersion: index.metadata?.version?.toString(),
    },
  };
}

/**
 * Process a single document
 */
function processDocument(
  doc: ScipDocument,
  nodes: Map<string, Node>,
  edges: Edge[]
): void {
  const language = doc.language || 'unknown';
  const filePath = doc.relative_path;

  // Create file node
  const fileNode: Node = {
    id: `file:${filePath}`,
    type: NodeType.File,
    name: filePath.split('/').pop() || filePath,
    language,
    filePath,
  };
  nodes.set(fileNode.id, fileNode);

  // Process symbol definitions from symbols array
  if (doc.symbols) {
    for (const sym of doc.symbols) {
      const node = symbolInfoToNode(sym, language, filePath);
      nodes.set(node.id, node);

      // Create defines edge from file to symbol
      edges.push({
        id: generateEdgeId(fileNode.id, node.id, EdgeType.Defines),
        type: EdgeType.Defines,
        sourceId: fileNode.id,
        targetId: node.id,
        filePath,
      });

      // Process relationships
      if (sym.relationships) {
        for (const rel of sym.relationships) {
          processRelationship(node.id, rel, edges, filePath);
        }
      }
    }
  }

  // Process occurrences
  if (doc.occurrences) {
    processOccurrences(doc.occurrences, language, filePath, nodes, edges, fileNode.id);
  }
}

/**
 * Process occurrences to extract references, imports, and calls
 */
function processOccurrences(
  occurrences: ScipOccurrence[],
  language: string,
  filePath: string,
  nodes: Map<string, Node>,
  edges: Edge[],
  fileNodeId: string
): void {
  for (const occ of occurrences) {
    if (!occ.symbol) continue;

    const symbolId = generateNodeId(occ.symbol);

    // Handle definitions
    if (isDefinition(occ)) {
      if (!nodes.has(symbolId)) {
        const node = occurrenceToNode(occ, language, filePath, 'unknown');
        if (node) {
          nodes.set(symbolId, node);
          edges.push({
            id: generateEdgeId(fileNodeId, symbolId, EdgeType.Defines),
            type: EdgeType.Defines,
            sourceId: fileNodeId,
            targetId: symbolId,
            filePath,
            line: occ.range[0],
            column: occ.range[1],
          });
        }
      }
    }
    // Handle imports
    else if (isImport(occ)) {
      edges.push({
        id: generateEdgeId(fileNodeId, symbolId, EdgeType.Imports),
        type: EdgeType.Imports,
        sourceId: fileNodeId,
        targetId: symbolId,
        filePath,
        line: occ.range[0],
        column: occ.range[1],
      });
    }
    // Handle references (calls or regular references)
    else if (isReference(occ) || (!isDefinition(occ) && !isImport(occ))) {
      const edgeType = detectCallEdge(occ) ? EdgeType.Calls : EdgeType.References;
      edges.push({
        id: generateEdgeId(fileNodeId, symbolId, edgeType),
        type: edgeType,
        sourceId: fileNodeId,
        targetId: symbolId,
        filePath,
        line: occ.range[0],
        column: occ.range[1],
      });
    }
  }
}

/**
 * Detect if an occurrence represents a function/method call
 */
function detectCallEdge(occ: ScipOccurrence): boolean {
  if (!occ.symbol) return false;

  try {
    const parsed = parseSymbol(occ.symbol);
    const lastDesc = parsed.descriptors[parsed.descriptors.length - 1];
    return lastDesc?.type === 'method' || lastDesc?.name.includes('(');
  } catch {
    return false;
  }
}

/**
 * Process symbol relationships
 */
function processRelationship(
  sourceId: string,
  rel: ScipRelationship,
  edges: Edge[],
  filePath: string
): void {
  const targetId = generateNodeId(rel.symbol);

  if (rel.is_implementation) {
    edges.push({
      id: generateEdgeId(sourceId, targetId, EdgeType.Implements),
      type: EdgeType.Implements,
      sourceId,
      targetId,
      filePath,
    });
  }

  if (rel.is_type_definition) {
    edges.push({
      id: generateEdgeId(sourceId, targetId, EdgeType.Extends),
      type: EdgeType.Extends,
      sourceId,
      targetId,
      filePath,
    });
  }

  if (rel.is_reference) {
    edges.push({
      id: generateEdgeId(sourceId, targetId, EdgeType.References),
      type: EdgeType.References,
      sourceId,
      targetId,
      filePath,
    });
  }
}

/**
 * Process external symbols
 */
function processExternalSymbol(
  sym: ScipSymbolInformation,
  nodes: Map<string, Node>
): void {
  const parsed = parseSymbol(sym.symbol);

  const node: Node = {
    id: generateNodeId(sym.symbol),
    type: getNodeTypeFromDescriptors(parsed.descriptors),
    name: extractNodeName(parsed),
    language: parsed.scheme.replace('scip-', ''),
    filePath: buildFilePath(parsed),
    documentation: sym.documentation,
    signature: sym.signature_documentation?.text,
    isExternal: true,
  };

  nodes.set(node.id, node);
}

/**
 * Parse SCIP index from protobuf bytes (requires protobuf decoder)
 */
export async function parseScipProtobuf(
  buffer: Buffer,
  decodeFn: (buffer: Buffer) => Promise<ScipIndex>
): Promise<ScipParseResult> {
  const index = await decodeFn(buffer);
  return parseScipIndex(index);
}

/**
 * Parse SCIP index from JSON representation
 */
export function parseScipJson(jsonString: string): ScipParseResult {
  const index: ScipIndex = JSON.parse(jsonString);
  return parseScipIndex(index);
}

/**
 * Get statistics about parsed result
 */
export function getParseStats(result: ScipParseResult): {
  nodeCount: number;
  edgeCount: number;
  nodeTypes: Record<string, number>;
  edgeTypes: Record<string, number>;
  languages: string[];
} {
  const nodeTypes: Record<string, number> = {};
  const edgeTypes: Record<string, number> = {};
  const languages = new Set<string>();

  for (const node of result.nodes) {
    nodeTypes[node.type] = (nodeTypes[node.type] || 0) + 1;
    if (node.language) {
      languages.add(node.language);
    }
  }

  for (const edge of result.edges) {
    edgeTypes[edge.type] = (edgeTypes[edge.type] || 0) + 1;
  }

  return {
    nodeCount: result.nodes.length,
    edgeCount: result.edges.length,
    nodeTypes,
    edgeTypes,
    languages: Array.from(languages),
  };
}
